// Cousine (Regular) — a metric-compatible Courier alternative with full Vietnamese
// and Latin-Extended coverage, merged from the SIL/Apache-licensed Cousine subsets.
// jsPDF's built-in 'courier' is a standard-14 font locked to WinAnsi (Latin-1), so any
// character outside Latin-1 (Vietnamese diacritics, etc.) is mangled. Embedding this
// TrueType font lets jsPDF render the full Unicode range. Advance width is exactly
// 0.6em (600/1000), i.e. 10 chars/inch at 12pt, so the screenplay layout math is unchanged.
export const COUSINE_TTF_BASE64 =
    '';
